import ast
from pathlib import Path
GENERIC_NAMES = {'data','result','temp','tmp','foo','bar','test','x','val','item'}
ROOT = Path('.')
NON_PRODUCTION_DIRS = {'tests','scripts','venv','node_modules','.venv','build','dist','.next','.cache','__pycache__','.git','.quality','docs','frontend','migrations','alembic'}
hits = []
for p in ROOT.rglob('*.py'):
    parts = p.parts
    if any(part in NON_PRODUCTION_DIRS for part in parts):
        continue
    try:
        tree = ast.parse(p.read_text())
    except Exception:
        continue
    for node in ast.walk(tree):
        if isinstance(node, ast.Name) and isinstance(getattr(node, 'ctx', None), ast.Store):
            if node.id in GENERIC_NAMES:
                hits.append((str(p), node.lineno, node.id))
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            if node.name in GENERIC_NAMES:
                hits.append((str(p), node.lineno, node.name))
print('total:', len(hits))
for h in hits:
    print(h)
"
